import React, { useState, useEffect, useRef } from 'react';
import { EngineState } from '../types';
import { Cpu, Zap, Wifi, CheckCircle2, Loader2, Sparkles, Terminal, Activity } from 'lucide-react';
import { GlassCard } from './GlassCard';

interface ProcessingHUDProps {
    state: EngineState;
}

const PIPELINE_STAGES = [
    { id: 1, title: "理解", desc: "全息语义拓扑解析与意图重构" },
    { id: 2, title: "架构", desc: "构建多维认知模型与逻辑骨架" },
    { id: 3, title: "增强", desc: "跨域知识向量高维注入" },
    { id: 4, title: "涌现", desc: "非线性思维奇点与灵感触发" },
    { id: 5, title: "优化", desc: "自指涉循环打磨与最终收敛" }
];

export const ProcessingHUD: React.FC<ProcessingHUDProps> = ({ state }) => {
    const isProcessing = state.status === 'PROCESSING';
    const isComplete = state.status === 'COMPLETE';

    // -1: Idle, 0-4: Stages, 5: All Complete
    const [currentStage, setCurrentStage] = useState(-1);
    const scrollRef = useRef<HTMLDivElement>(null);

    // Auto-scroll logs
    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [state.logs]);

    // Reset or Sync State
    useEffect(() => {
        if (state.status === 'IDLE' || state.status === 'ACTIVATING') {
            setCurrentStage(-1);
        } else if (isProcessing) {
             if (currentStage === -1) setCurrentStage(0);
        } else if (isComplete) {
            setCurrentStage(PIPELINE_STAGES.length);
        }
    }, [state.status, isProcessing, isComplete]);

    // Timer Logic for Sequential Pipeline (Visual only now)
    useEffect(() => {
        let interval: NodeJS.Timeout;
        if (isProcessing && currentStage >= 0 && currentStage < PIPELINE_STAGES.length - 1) {
            interval = setInterval(() => {
                setCurrentStage(prev => {
                    if (prev < PIPELINE_STAGES.length - 1) {
                        return prev + 1;
                    }
                    return prev;
                });
            }, 1200);
        }
        return () => clearInterval(interval);
    }, [isProcessing, currentStage]);

    // Calculate progress percentage for the bar (0 to 100)
    const progressPercent = Math.min(100, Math.max(0, (currentStage / (PIPELINE_STAGES.length - 1)) * 100));

    return (
        <GlassCard className="h-full flex flex-col p-5 md:p-6 shadow-glass-xl border-white/20 ring-1 ring-white/10 relative overflow-hidden" intensity="lg">
            {/* Background Icon Decoration */}
            <div className={`absolute -bottom-8 -right-8 text-white/5 text-6xl md:text-9xl transition-transform duration-[2000ms] ease-in-out pointer-events-none ${isProcessing ? 'rotate-12 scale-110' : 'rotate-0 scale-100'}`}>
                <Activity />
            </div>

            {/* Header Status */}
            <div className="flex items-center justify-between mb-4 relative z-10 shrink-0">
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <div className={`w-3 h-3 rounded-full transition-all duration-500 ${isProcessing ? 'bg-apple-cyan shadow-[0_0_12px_rgba(100,210,255,0.6)]' : 'bg-apple-gray/40 shadow-inner'}`}></div>
                        {isProcessing && <div className="absolute inset-0 rounded-full bg-apple-cyan animate-ping opacity-75"></div>}
                    </div>
                    <span className="text-xs md:text-sm font-bold tracking-widest text-apple-text/90 uppercase drop-shadow-sm">System Core</span>
                </div>
                <div className={`flex items-center gap-2 px-2 py-1 md:px-3 md:py-1.5 rounded-full border backdrop-blur-md transition-all duration-500 ${isProcessing ? 'bg-white/10 border-apple-blue/30 shadow-glass-sm' : 'bg-white/5 border-white/10'}`}>
                     <Wifi size={14} className={isProcessing ? 'text-apple-blue animate-pulse' : 'text-apple-gray/70'} />
                     <span className="text-[10px] font-mono font-semibold text-apple-gray">{isProcessing ? 'ONLINE' : 'STANDBY'}</span>
                </div>
            </div>

            {/* Main Metrics Area */}
            <div className="flex-1 flex flex-col gap-4 relative z-10 overflow-hidden">
                {/* Charts Area */}
                <div className="grid grid-cols-2 gap-3 md:gap-4 shrink-0">
                    {/* Neural Load */}
                    <div className="group relative bg-white/5 rounded-xl p-3 border border-white/5 overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-br from-apple-blue/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                        <div className="flex justify-between text-[10px] md:text-xs mb-2 font-medium text-apple-text/80 relative z-10">
                            <span className="flex items-center gap-1.5">
                                <Cpu size={14} className={`text-apple-blue transition-all duration-1000 ${isProcessing ? 'animate-[spin_3s_linear_infinite]' : 'opacity-70'}`}/>
                                <span className="tracking-wide">Neural Load</span>
                            </span>
                            <span className="font-mono font-bold text-apple-text">{isProcessing ? Math.floor(Math.random() * 30 + 60) : 5}%</span>
                        </div>
                        <div className="h-1.5 w-full bg-black/20 rounded-full overflow-hidden border border-white/5 relative z-10">
                            <div 
                                className="h-full bg-gradient-to-r from-apple-blue via-apple-cyan to-white/90 transition-all duration-300 rounded-full shadow-[0_0_10px_rgba(10,132,255,0.5)]"
                                style={{ width: `${isProcessing ? Math.random() * 30 + 60 : 5}%` }}
                            />
                        </div>
                    </div>

                    {/* Coherence */}
                    <div className="group relative bg-white/5 rounded-xl p-3 border border-white/5 overflow-hidden">
                         <div className="absolute inset-0 bg-gradient-to-br from-apple-purple/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                        <div className="flex justify-between text-[10px] md:text-xs mb-2 font-medium text-apple-text/80 relative z-10">
                            <span className="flex items-center gap-1.5">
                                <Zap size={14} className={`text-apple-purple transition-all duration-500 ${isProcessing ? 'animate-pulse scale-110' : 'opacity-70'}`}/>
                                <span className="tracking-wide">Coherence</span>
                            </span>
                            <span className="font-mono font-bold text-apple-text">{isProcessing ? Math.floor(Math.random() * 20 + 75) : 12}%</span>
                        </div>
                        <div className="h-1.5 w-full bg-black/20 rounded-full overflow-hidden border border-white/5 relative z-10">
                            <div 
                                className="h-full bg-gradient-to-r from-apple-purple via-pink-500 to-white/90 transition-all duration-500 rounded-full shadow-[0_0_10px_rgba(94,92,230,0.5)]"
                                style={{ width: `${isProcessing ? Math.random() * 20 + 75 : 12}%` }}
                            />
                        </div>
                    </div>
                </div>

                {/* Horizontal Pipeline Visualizer (Condensed) */}
                <div className="relative group rounded-xl bg-black/20 border border-white/10 overflow-hidden flex flex-col px-4 py-3 shrink-0">
                    <div className="flex justify-between items-center mb-3 shrink-0">
                        <span className="text-[10px] font-mono uppercase tracking-widest text-apple-gray/70">Sequence Topology</span>
                        {isProcessing && <Loader2 size={10} className="animate-spin text-apple-blue/50" />}
                    </div>

                    <div className="relative px-1 pb-2">
                        {/* Track */}
                        <div className="absolute top-[5px] left-[6px] right-[6px] h-[2px] bg-white/5 rounded-full"></div>
                        <div className="absolute top-[5px] left-[6px] right-[6px] h-[2px] rounded-full overflow-hidden">
                             <div 
                                className="h-full bg-gradient-to-r from-apple-blue to-apple-cyan transition-all duration-700 ease-out origin-left"
                                style={{ width: `${progressPercent}%` }} 
                             ></div>
                        </div>

                        {/* Steps */}
                        <div className="relative flex justify-between items-start z-10">
                            {PIPELINE_STAGES.map((stage, index) => {
                                const isActive = isProcessing && currentStage === index;
                                const isCompleted = currentStage > index || isComplete;

                                return (
                                    <div key={stage.id} className="flex flex-col items-center gap-2 group/step w-8">
                                        <div className={`
                                            w-3 h-3 rounded-full border-[2px] transition-all duration-500 relative z-20
                                            ${isActive 
                                                ? 'bg-apple-blue border-apple-blue scale-125 shadow-[0_0_15px_rgba(10,132,255,0.8)] animate-pulse' 
                                                : isCompleted 
                                                    ? 'bg-apple-blue border-apple-blue opacity-50' 
                                                    : 'bg-[#1c1c1e] border-white/10'
                                            }
                                        `}>
                                            {isActive && <div className="absolute inset-0 bg-apple-blue animate-ping rounded-full opacity-50"></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>

                {/* NEW: Real-time Terminal Log (Replaces static description) */}
                 <div className="flex-1 relative rounded-lg bg-[#0c0c0e] border border-white/10 p-3 flex flex-col gap-2 overflow-hidden shadow-inner">
                    {/* Header */}
                    <div className="flex items-center justify-between border-b border-white/5 pb-2 mb-1 shrink-0">
                         <div className="flex items-center gap-2">
                            <Terminal size={12} className="text-apple-gray" />
                            <span className="text-[10px] font-mono font-bold text-apple-gray uppercase tracking-widest">System_Log.sh</span>
                         </div>
                         <div className="flex gap-1.5 opacity-50">
                            <div className="w-1.5 h-1.5 rounded-full bg-red-500"></div>
                            <div className="w-1.5 h-1.5 rounded-full bg-yellow-500"></div>
                            <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
                         </div>
                    </div>

                    {/* Scrolling Content */}
                    <div 
                        ref={scrollRef}
                        className="flex-1 overflow-y-auto font-mono text-[10px] md:text-xs space-y-1.5 custom-scrollbar scroll-smooth min-h-0"
                    >
                        {state.logs.length === 0 ? (
                             <div className="h-full flex flex-col items-center justify-center text-apple-gray/20 gap-2">
                                <Activity size={16} />
                                <span className="italic">Awaiting Input Stream...</span>
                             </div>
                        ) : (
                            <div className="flex flex-col gap-1.5 pb-2">
                                {state.logs.map((log, i) => (
                                    <div key={i} className="flex items-start gap-2 animate-in slide-in-from-left-2 duration-300">
                                        <span className="text-apple-gray/30 select-none shrink-0 text-[9px] mt-0.5">{(i + 1).toString().padStart(3, '0')}</span>
                                        <span className={`leading-relaxed break-words ${
                                            i === state.logs.length - 1 
                                                ? 'text-apple-cyan drop-shadow-[0_0_5px_rgba(100,210,255,0.5)]' 
                                                : 'text-apple-gray/70'
                                        }`}>
                                            {log.startsWith('>') ? (
                                                <>
                                                    <span className="text-apple-blue/50 mr-1.5">›</span>
                                                    {log.substring(1).trim()}
                                                </>
                                            ) : (
                                                log
                                            )}
                                        </span>
                                    </div>
                                ))}
                                {isProcessing && (
                                    <div className="pl-6 pt-1">
                                        <div className="w-2 h-4 bg-apple-cyan/50 animate-pulse"></div>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>

            </div>
        </GlassCard>
    );
};

import React, { useState, useCallback, useRef } from 'react';
import { SystemMode, EngineState, GenerationResult } from './types';
import { generateUltimatePrompt, extractTextFromImage } from './services/geminiService';
import { ProcessingHUD } from './components/ProcessingHUD';
import { ResultView } from './components/ResultView';
import { GlassCard } from './components/GlassCard';
import { Hexagon, Layers, Sparkles, Image as ImageIcon, Loader2, ImagePlus, CheckCircle2, History, Power, User, Lightbulb, Box, Mountain, Palette } from 'lucide-react';
import { MODE_DESCRIPTIONS } from './constants';
import { HistoryModal } from './components/HistoryModal';

const INITIAL_LOGS = [
    "> 系统初始化...",
    "> 加载认知核心...",
    "> 连接量子场...",
    "> 等待输入"
];

const App: React.FC = () => {
    // Structured Input State
    const [inputs, setInputs] = useState({
        role: '世界知名的展馆设计大师',
        vibe: '兼具科学性和美观性，核心创意是讲述港口里包含的基础科学内容',
        subject: '一个大型机械装置',
        environment: '宁波北仑的科技博物馆中的序厅，未来主义的现代中庭大堂',
        style: '广角建筑摄影，展示方案，中英文对照'
    });

    const [mode, setMode] = useState<SystemMode>(SystemMode.SINGULARITY);
    const [engineState, setEngineState] = useState<EngineState>({
        status: 'IDLE',
        logs: INITIAL_LOGS,
        progress: 0
    });
    const [result, setResult] = useState<GenerationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    // History State
    const [history, setHistory] = useState<GenerationResult[]>([]);
    const [showHistory, setShowHistory] = useState(false);

    // OCR State
    const [isExtracting, setIsExtracting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Style Reference State
    const [styleImage, setStyleImage] = useState<{ data: string, mimeType: string } | null>(null);
    const styleInputRef = useRef<HTMLInputElement>(null);

    const handleInputChange = (field: keyof typeof inputs, value: string) => {
        setInputs(prev => ({ ...prev, [field]: value }));
    };

    const constructTopic = () => {
        return `
[Part 1: 🧙‍♂️ 召唤 AI 角色身份] You are a ${inputs.role}. Create a concept design for an exhibition space.
[Part 2: ✨ 核心氛围与创意脑洞] The vibe is ${inputs.vibe}.
[Part 3: 🏛️ 画面主体描述] The scene features ${inputs.subject}, surrounded by ${inputs.environment}.
[Part 4: 💎 质感与光影魔法] Use ${inputs.style} and special lighting to create a magical atmosphere.
        `.trim();
    };

    const addLog = useCallback((message: string) => {
        setEngineState(prev => ({
            ...prev,
            logs: [...prev.logs, `> ${message}`]
        }));
    }, []);

    const simulateProcessingSteps = async () => {
        const steps = [
            { msg: "激活超级提示引擎...", p: 10, delay: 800 },
            { msg: `初始化模式: [${mode}]`, p: 20, delay: 600 },
            { msg: "深度推理层: 激活", p: 35, delay: 1000 },
            { msg: "探索量子可能性...", p: 50, delay: 1200 },
            { msg: "识别模式...", p: 65, delay: 900 },
            { msg: "合成涌现...", p: 80, delay: 1100 },
            { msg: "递归优化循环...", p: 90, delay: 800 },
            { msg: "结晶输出...", p: 98, delay: 600 },
        ];

        for (const step of steps) {
            if (error) break;
            addLog(step.msg);
            setEngineState(prev => ({ ...prev, progress: step.p }));
            await new Promise(resolve => setTimeout(resolve, step.delay));
        }
    };

    const handleActivate = async () => {
        const fullTopic = constructTopic();
        if (!fullTopic.trim()) return;

        setEngineState({ status: 'PROCESSING', logs: [], progress: 0 });
        setResult(null);
        setError(null);

        const animationPromise = simulateProcessingSteps();

        try {
            if (styleImage) {
                addLog("注入视觉参考向量...");
            }
            const content = await generateUltimatePrompt(fullTopic, mode, styleImage);
            await animationPromise;

            const newResult: GenerationResult = {
                content,
                metadata: {
                    mode,
                    timestamp: new Date().toISOString(),
                    metrics: {
                        consciousness: "MAXIMUM",
                        recursion: "INFINITE",
                        emergence: "UNBOUNDED"
                    }
                }
            };

            setResult(newResult);
            setHistory(prev => [newResult, ...prev]);

            setEngineState(prev => ({
                status: 'COMPLETE',
                logs: [...prev.logs, "> 执行成功", "> 输出已生成"],
                progress: 100
            }));

        } catch (err: any) {
            setError(err.message || "Unknown error occurred");
            setEngineState(prev => ({
                status: 'ERROR',
                logs: [...prev.logs, `! 严重错误: ${err.message}`],
                progress: 0
            }));
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件");
            return;
        }

        setIsExtracting(true);
        addLog("正在解析图像内容...");

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            const extractedText = await extractTextFromImage(base64, file.type);

            if (!extractedText.trim()) {
                addLog("! 警告: 未识别到文字");
            } else {
                setInputs(prev => ({
                    ...prev,
                    subject: prev.subject 
                        ? `${prev.subject} (参考: ${extractedText.trim()})`
                        : extractedText.trim()
                }));
                addLog("图像文字提取成功");
            }
        } catch (err: any) {
            console.error(err);
            addLog(`! 识别失败: ${err.message}`);
        } finally {
            setIsExtracting(false);
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
            }
        }
    };

    const handleStyleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            addLog("! 错误: 仅支持图片文件作为参考");
            return;
        }

        addLog("正在分析视觉参考...");

        try {
            const base64 = await new Promise<string>((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = () => {
                    const result = reader.result as string;
                    resolve(result.split(',')[1]);
                };
                reader.onerror = reject;
                reader.readAsDataURL(file);
            });

            setStyleImage({
                data: base64,
                mimeType: file.type
            });
            addLog("视觉风格参考已加载");
        } catch (err: any) {
            console.error(err);
            addLog(`! 参考图加载失败: ${err.message}`);
        } finally {
            if (styleInputRef.current) {
                styleInputRef.current.value = '';
            }
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    const triggerStyleInput = () => {
        styleInputRef.current?.click();
    };

    const isFormValid = Object.values(inputs).some(val => val.trim().length > 0);

    return (
        <div className="min-h-screen p-3 md:p-8 lg:p-12 flex items-center justify-center">
            {/* 
               Responsive Grid Strategy:
               Mobile: grid-cols-3. 
               Desktop: grid-cols-6.
            */}
            <div className="w-full max-w-[1200px] h-full grid grid-cols-3 md:grid-cols-6 md:grid-rows-[auto_auto_auto] gap-4 md:gap-6 auto-rows-auto md:auto-rows-fr">

                {/* --- GRID AREA A: CORE INTELLIGENCE (MAIN CARD) --- */}
                <GlassCard className="col-span-3 md:col-span-3 md:row-span-2 flex flex-col p-5 md:p-8 relative min-h-[400px] md:min-h-0" intensity="lg">
                    {/* Background Graphic */}
                    <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none transform translate-x-10 -translate-y-10">
                        <i className="fa-solid fa-brain text-[8rem] md:text-[12rem] text-apple-blue"></i>
                    </div>

                    {/* Style Reference & History Buttons (Top Right) */}
                    <div className="absolute top-4 right-4 md:top-6 md:right-6 z-20 flex flex-col items-end gap-2">
                        {/* Style Reference Button */}
                        <div className="relative">
                            <input
                                type="file"
                                ref={styleInputRef}
                                className="hidden"
                                accept="image/*"
                                onChange={handleStyleImageUpload}
                            />
                            <button
                                onClick={triggerStyleInput}
                                disabled={engineState.status === 'PROCESSING'}
                                className={`flex items-center gap-2 px-2.5 py-2 md:px-3 md:py-2 rounded-full backdrop-blur-md transition-all duration-300 shadow-sm border ${
                                    styleImage 
                                    ? 'bg-apple-blue/20 border-apple-blue/50 text-apple-blue hover:bg-apple-blue/30' 
                                    : 'bg-white/10 border-white/20 text-apple-gray hover:bg-white/20 hover:text-apple-blue'
                                } ${engineState.status === 'PROCESSING' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                title={styleImage ? "点击更换参考图" : "上传参考图以提取风格"}
                            >
                                {styleImage ? (
                                    <>
                                        <CheckCircle2 size={16} />
                                        <span className="hidden md:inline text-xs font-bold">视觉参考已就绪</span>
                                        <span className="md:hidden text-xs font-bold">已就绪</span>
                                    </>
                                ) : (
                                    <>
                                        <ImagePlus size={16} />
                                        <span className="hidden md:inline text-xs font-medium">上传风格参考</span>
                                        <span className="md:hidden text-xs font-medium">参考图</span>
                                    </>
                                )}
                            </button>
                        </div>

                        {/* History Button */}
                        <button
                            onClick={() => setShowHistory(true)}
                            disabled={engineState.status === 'PROCESSING'}
                            className="flex items-center gap-2 px-2.5 py-2 md:px-3 md:py-2 rounded-full backdrop-blur-md transition-all duration-300 shadow-sm border bg-white/10 border-white/20 text-apple-gray hover:bg-white/20 hover:text-apple-blue disabled:opacity-50 disabled:cursor-not-allowed"
                            title="查看历史记录"
                        >
                            <History size={16} />
                            <span className="hidden md:inline text-xs font-medium">历史记录</span>
                        </button>
                    </div>

                    <div className="relative z-10 flex flex-col h-full mt-2">
                        <div className="mb-4">
                            <h1 className="text-xl md:text-2xl font-extrabold tracking-tight text-apple-text mb-1 bg-clip-text text-transparent bg-gradient-to-r from-apple-text to-apple-gray font-sc">
                                认知极限系统 V3.0
                            </h1>
                            <div className="flex items-center gap-2">
                                <span className="text-apple-gray text-[10px] md:text-xs font-medium uppercase tracking-wider">Advanced Prompt Engineering</span>
                            </div>
                        </div>

                        {/* 5-Field Input Grid */}
                        <div className="relative flex-1 w-full mb-4 grid grid-cols-1 gap-2.5 overflow-y-auto pr-1 custom-scrollbar max-h-[400px]">

                            {/* Input 1: Role */}
                            <div className="space-y-1">
                                <label className="flex items-center gap-1.5 text-[10px] uppercase font-bold text-apple-blue/90 tracking-wider">
                                    <User size={10} />
                                    <span>Part 1: 召唤角色身份</span>
                                </label>
                                <div className="relative group/input">
                                    <textarea
                                        value={inputs.role}
                                        onChange={(e) => handleInputChange('role', e.target.value)}
                                        placeholder="例如：世界知名的展馆设计大师"
                                        className="w-full bg-white/5 border border-white/10 rounded-lg p-2.5 text-xs md:text-sm text-apple-text placeholder-apple-gray/30 focus:outline-none focus:ring-1 focus:ring-apple-blue/50 focus:bg-white/10 transition-all resize-none min-h-[50px] leading-relaxed"
                                        disabled={engineState.status === 'PROCESSING'}
                                    />
                                    <div className="absolute right-2 top-2 text-[9px] text-white/10 pointer-events-none font-mono">You are a...</div>
                                </div>
                            </div>

                            {/* Input 2: Vibe & Concept */}
                            <div className="space-y-1">
                                <label className="flex items-center gap-1.5 text-[10px] uppercase font-bold text-apple-purple/90 tracking-wider">
                                    <Lightbulb size={10} />
                                    <span>Part 2: 核心氛围与脑洞</span>
                                </label>
                                <div className="relative group/input">
                                    <textarea
                                        value={inputs.vibe}
                                        onChange={(e) => handleInputChange('vibe', e.target.value)}
                                        placeholder="例如：兼具科学性与美观性，讲述港口基础科学..."
                                        className="w-full bg-white/5 border border-white/10 rounded-lg p-2.5 text-xs md:text-sm text-apple-text placeholder-apple-gray/30 focus:outline-none focus:ring-1 focus:ring-apple-purple/50 focus:bg-white/10 transition-all resize-none min-h-[60px] leading-relaxed"
                                        disabled={engineState.status === 'PROCESSING'}
                                    />
                                </div>
                            </div>

                            {/* Input 3: Subject (With OCR) */}
                            <div className="space-y-1">
                                <div className="flex justify-between items-center">
                                    <label className="flex items-center gap-1.5 text-[10px] uppercase font-bold text-green-400/90 tracking-wider">
                                        <Box size={10} />
                                        <span>Part 3: 画面主体</span>
                                    </label>
                                    <input
                                        type="file"
                                        ref={fileInputRef}
                                        className="hidden"
                                        accept="image/*"
                                        onChange={handleImageUpload}
                                    />
                                    <button
                                        onClick={triggerFileInput}
                                        disabled={isExtracting || engineState.status === 'PROCESSING'}
                                        className="flex items-center gap-1 px-1.5 py-0.5 rounded bg-white/5 hover:bg-white/10 text-[9px] text-apple-gray hover:text-white transition-colors border border-white/5"
                                        title="上传图片提取主体描述"
                                    >
                                        {isExtracting ? <Loader2 size={8} className="animate-spin" /> : <ImageIcon size={8} />}
                                        <span>{isExtracting ? '提取中' : '图片识别'}</span>
                                    </button>
                                </div>
                                <div className="relative group/input">
                                    <textarea
                                        value={inputs.subject}
                                        onChange={(e) => handleInputChange('subject', e.target.value)}
                                        placeholder="例如：一个大型机械装置"
                                        className="w-full bg-white/5 border border-white/10 rounded-lg p-2.5 text-xs md:text-sm text-apple-text placeholder-apple-gray/30 focus:outline-none focus:ring-1 focus:ring-green-500/50 focus:bg-white/10 transition-all resize-none min-h-[50px] leading-relaxed"
                                        disabled={engineState.status === 'PROCESSING'}
                                    />
                                </div>
                            </div>

                             {/* Input 4: Environment */}
                             <div className="space-y-1">
                                <label className="flex items-center gap-1.5 text-[10px] uppercase font-bold text-orange-400/90 tracking-wider">
                                    <Mountain size={10} />
                                    <span>Part 4: 环境细节</span>
                                </label>
                                <div className="relative group/input">
                                    <textarea
                                        value={inputs.environment}
                                        onChange={(e) => handleInputChange('environment', e.target.value)}
                                        placeholder="例如：未来主义的现代中庭大堂..."
                                        className="w-full bg-white/5 border border-white/10 rounded-lg p-2.5 text-xs md:text-sm text-apple-text placeholder-apple-gray/30 focus:outline-none focus:ring-1 focus:ring-orange-400/50 focus:bg-white/10 transition-all resize-none min-h-[50px] leading-relaxed"
                                        disabled={engineState.status === 'PROCESSING'}
                                    />
                                </div>
                            </div>

                             {/* Input 5: Style */}
                             <div className="space-y-1">
                                <label className="flex items-center gap-1.5 text-[10px] uppercase font-bold text-cyan-400/90 tracking-wider">
                                    <Palette size={10} />
                                    <span>Part 5: 质感与光影</span>
                                </label>
                                <div className="relative group/input">
                                    <textarea
                                        value={inputs.style}
                                        onChange={(e) => handleInputChange('style', e.target.value)}
                                        placeholder="例如：广角建筑摄影，光影魔法..."
                                        className="w-full bg-white/5 border border-white/10 rounded-lg p-2.5 text-xs md:text-sm text-apple-text placeholder-apple-gray/30 focus:outline-none focus:ring-1 focus:ring-cyan-400/50 focus:bg-white/10 transition-all resize-none min-h-[50px] leading-relaxed"
                                        disabled={engineState.status === 'PROCESSING'}
                                    />
                                </div>
                            </div>

                        </div>

                        <button 
                            onClick={handleActivate}
                            disabled={!isFormValid || engineState.status === 'PROCESSING'}
                            className={`
                                group relative w-full py-4 rounded-xl font-bold tracking-wide transition-all duration-300 overflow-hidden shadow-lg border mt-auto shrink-0
                                ${!isFormValid 
                                    ? 'bg-gray-800 text-gray-500 cursor-not-allowed border-gray-700' 
                                    : engineState.status === 'PROCESSING'
                                        ? 'bg-black text-white border-red-500/50 shadow-[0_0_40px_rgba(239,68,68,0.4)] scale-[0.99]'
                                        : 'bg-apple-text text-black hover:shadow-[0_0_25px_rgba(255,255,255,0.3)] border-transparent hover:scale-[1.01] active:scale-[0.98]'
                                }
                            `}
                        >
                            {/* ENGINE PROCESSING VISUALS */}
                            {engineState.status === 'PROCESSING' && (
                                <>
                                     <div className="absolute inset-0 bg-gradient-to-r from-transparent via-red-500/50 to-transparent w-[200%] h-full animate-shimmer skew-x-12 opacity-80"></div>
                                     <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[200%] bg-red-500/20 rounded-full animate-[ping_0.8s_cubic-bezier(0,0,0.2,1)_1]"></div>
                                     <div className="absolute inset-0 bg-red-500/5 animate-pulse"></div>
                                </>
                            )}

                            {/* HOVER VISUALS (IDLE) */}
                            {engineState.status !== 'PROCESSING' && isFormValid && (
                                <div className="absolute inset-0 bg-gradient-to-r from-apple-blue to-apple-purple opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                            )}

                            <div className="relative z-10 flex items-center justify-center gap-3">
                                {engineState.status === 'PROCESSING' ? (
                                    <>
                                        <div className="relative">
                                            <Power size={20} className="text-red-500 animate-[spin_3s_linear_infinite]" strokeWidth={3} />
                                            <div className="absolute inset-0 bg-red-500 blur-md opacity-60 animate-pulse"></div>
                                        </div>
                                        <span className="text-red-500 tracking-widest text-base font-bold animate-pulse">
                                            引擎高能运行中
                                        </span>
                                    </>
                                ) : (
                                    <>
                                        <div className={`p-1 rounded-full border-[2.5px] border-current transition-all duration-500 ${!isFormValid ? 'opacity-50' : 'group-hover:border-white group-hover:rotate-90 group-hover:scale-110'}`}>
                                            <Power size={16} className={`transition-colors ${!isFormValid ? '' : 'group-hover:text-white'}`} strokeWidth={3} />
                                        </div>
                                        <span className={`text-base md:text-lg transition-colors ${!isFormValid ? '' : 'group-hover:text-white'}`}>
                                            激活认知引擎
                                        </span>
                                    </>
                                )}
                            </div>
                        </button>
                    </div>
                </GlassCard>

                {/* --- GRID AREA B: MODE - SINGULARITY --- */}
                {/* Mobile: 1 col (1/3 width), Desktop: 1 col */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.SINGULARITY)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.SINGULARITY ? 'ring-2 ring-apple-blue ring-offset-2 ring-offset-black' : 'opacity-70 hover:opacity-100'}`}
                >
                    <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.SINGULARITY ? 'bg-apple-blue text-white shadow-lg shadow-apple-blue/30' : 'bg-white/10 text-apple-gray'}`}>
                            <Hexagon size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.SINGULARITY && <div className="w-1.5 h-1.5 rounded-full bg-apple-blue animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA C: MODE - METAMORPHOSIS --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.METAMORPHOSIS)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.METAMORPHOSIS ? 'ring-2 ring-apple-purple ring-offset-2 ring-offset-black' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.METAMORPHOSIS ? 'bg-apple-purple text-white shadow-lg shadow-apple-purple/30' : 'bg-white/10 text-apple-gray'}`}>
                            <Layers size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.METAMORPHOSIS && <div className="w-1.5 h-1.5 rounded-full bg-apple-purple animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA D: MODE - ZENITH --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.ZENITH)}
                    className={`col-span-1 md:col-span-1 md:row-span-1 p-3 md:p-5 flex flex-col justify-between min-h-[140px] md:min-h-[auto] ${mode === SystemMode.ZENITH ? 'ring-2 ring-green-500 ring-offset-2 ring-offset-black' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start mb-2 md:mb-0">
                         <div className={`p-2 md:p-2.5 rounded-2xl ${mode === SystemMode.ZENITH ? 'bg-green-500 text-white shadow-lg shadow-green-500/30' : 'bg-white/10 text-apple-gray'}`}>
                            <Sparkles size={16} className="md:w-5 md:h-5" />
                        </div>
                        {mode === SystemMode.ZENITH && <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-sm md:text-base text-apple-text mb-0.5">{MODE_DESCRIPTIONS[SystemMode.ZENITH].label}</h3>
                        <p className="text-[9px] md:text-[10px] text-apple-gray leading-tight line-clamp-3 md:line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.ZENITH].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA E: HUD --- */}
                {/* Mobile: Full width (3 cols), Desktop: 3 cols */}
                <div className="col-span-3 md:col-span-3 md:row-span-1">
                    <ProcessingHUD state={engineState} />
                </div>

                {/* --- GRID AREA F: OUTPUT --- */}
                {/* Mobile: Full width (3 cols), Desktop: Full width (6 cols) */}
                <div className="col-span-3 md:col-span-6 md:row-span-1 h-full min-h-[300px]">
                    <ResultView result={result} />
                </div>

            </div>

            {/* History Modal */}
            <HistoryModal 
                isOpen={showHistory} 
                onClose={() => setShowHistory(false)} 
                history={history}
                onSelect={setResult}
            />
        </div>
    );
};

export default App;
